const { Client, Intents } = require('discord.js');
const { REST } = require('@discordjs/rest');
const { Routes } = require('discord-api-types/v9');
const { SlashCommandBuilder } = require('@discordjs/builders');

const client = new Client({ intents: [Intents.FLAGS.GUILDS] });
const commands = [
    new SlashCommandBuilder()
        .setName('ban')
        .setDescription('Ban a user')
        .addUserOption(option => option.setName('user').setDescription('The user to ban').setRequired(true))
        .addStringOption(option => option.setName('reason').setDescription('Reason for the ban')),
].map(command => command.toJSON());

const rest = new REST({ version: '9' }).setToken('YOUR_TOKEN');

(async () => {
    try {
        console.log('Started refreshing application (/) commands.');

        await rest.put(
            Routes.applicationGuildCommands('YOUR_CLIENT_ID', 'YOUR_GUILD_ID'),
            { body: commands },
        );

        console.log('Successfully reloaded application (/) commands.');
    } catch (error) {
        console.error(error);
    }
})();

client.on('interactionCreate', async interaction => {
    if (!interaction.isCommand()) return;

    const { commandName, options } = interaction;

    if (commandName === 'ban') {
        const user = options.getUser('user');
        const reason = options.getString('reason') || 'No reason provided';
        // Add your ban logic here using the user and reason
        interaction.reply(`${user.username} has been banned for: ${reason}`);
    }
});

client.login('YOUR_TOKEN');
```

Replace `YOUR_TOKEN`, `YOUR_CLIENT_ID`, and `YOUR_GUILD_ID` with your bot's token, client ID, and guild ID respectively. This code sets up a bot with a single slash command for banning users and handles the ban logic in the `interactionCreate` event.

